import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Button } from '../design-system/Button/Button';
import { Card } from '../design-system/Card/Card';
import { Badge, Tabs } from '../design-system/Badge/Badge';
import { Input } from '../design-system/Input/Input';
import '../theme/variables.css';

const AI = 'http://localhost:8000';

function WorkflowPanel() {
  const [diagnosis, setDiagnosis] = useState('');
  const [assessment, setAssessment] = useState('');
  const [age, setAge] = useState('40');
  const [meds, setMeds] = useState('');
  const [allergies, setAllergies] = useState('');
  const [workflow, setWorkflow] = useState<any>(null);
  const [rx, setRx] = useState<any>(null);
  const [labs, setLabs] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [tab, setTab] = useState('workflow');
  const [accepted, setAccepted] = useState<Set<string>>(new Set());

  const handlePredict = async () => {
    setError(null); setLoading(true);
    try {
      const ctx = { diagnosis, assessment, patient_age: parseInt(age)||40, medications: meds, allergies };
      const [w, r, l] = await Promise.all([
        fetch(`${AI}/api/v1/workflow/predict`, { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({...ctx, patient_sex:'U'}) }).then(r=>r.json()),
        fetch(`${AI}/api/v1/prescription/suggest`, { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({...ctx, patient_age:parseInt(age)||40}) }).then(r=>r.json()),
        fetch(`${AI}/api/v1/lab/suggest`, { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(ctx) }).then(r=>r.json()),
      ]);
      setWorkflow(w); setRx(r); setLabs(l); setAccepted(new Set());
    } catch(e:any) { setError(e.message); }
    finally { setLoading(false); }
  };

  const toggle = (key: string) => setAccepted(p => { const n = new Set(p); n.has(key) ? n.delete(key) : n.add(key); return n; });

  return (
    <div style={{maxWidth:800,margin:'0 auto',padding:'var(--spacing-4)'}}>
      <h1 style={{fontSize:'var(--font-size-2xl)',marginBottom:'var(--spacing-4)'}}>AI Workflow Prediction</h1>

      <Card title="Encounter Context">
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'var(--spacing-3)'}}>
          <Input label="Diagnosis" value={diagnosis} onChange={e=>setDiagnosis(e.target.value)} placeholder="e.g. Type 2 diabetes, hypertension" />
          <Input label="Patient Age" value={age} onChange={e=>setAge(e.target.value)} type="number" />
          <Input label="Assessment" value={assessment} onChange={e=>setAssessment(e.target.value)} placeholder="e.g. A1C 7.8, BP 142/88" />
          <Input label="Allergies" value={allergies} onChange={e=>setAllergies(e.target.value)} placeholder="e.g. Penicillin, Sulfa" />
        </div>
        <div style={{marginTop:'var(--spacing-2)'}}>
          <Input label="Current Medications" value={meds} onChange={e=>setMeds(e.target.value)} placeholder="e.g. Metformin 500mg BID" />
        </div>
        <div style={{marginTop:'var(--spacing-3)'}}>
          <Button onClick={handlePredict} disabled={!diagnosis || loading}>{loading ? 'Analyzing...' : 'Predict Actions'}</Button>
          {workflow?.mock && <span style={{marginLeft:8}}><Badge variant="warning">Offline mode</Badge></span>}
        </div>
        {error && <div style={{marginTop:8,padding:8,background:'var(--color-error-light)',borderRadius:4,color:'var(--color-error)',fontSize:14}}>{error}</div>}
      </Card>

      {(workflow || rx || labs) && (
        <div style={{marginTop:'var(--spacing-4)'}}>
          <Tabs tabs={[
            {key:'workflow',label:`Actions (${(workflow?.prescriptions?.length||0)+(workflow?.lab_orders?.length||0)+(workflow?.referrals?.length||0)})`},
            {key:'rx',label:`Prescriptions (${rx?.suggestions?.length||0})`},
            {key:'labs',label:`Labs (${labs?.suggestions?.length||0})`},
          ]} activeKey={tab} onChange={setTab} />

          <div style={{marginTop:'var(--spacing-4)'}}>
            {tab === 'workflow' && workflow && (
              <div style={{display:'flex',flexDirection:'column',gap:'var(--spacing-4)'}}>
                {workflow.prescriptions?.length > 0 && (
                  <Card title="Prescriptions">
                    {workflow.prescriptions.map((p:any,i:number) => (
                      <Item key={`rx-${i}`} label={p.drug} sub={`${p.dose} ${p.route} ${p.frequency} x ${p.duration}`} detail={p.rationale} conf={p.confidence} accepted={accepted} onToggle={()=>toggle(`rx-${i}`)} />
                    ))}
                  </Card>
                )}
                {workflow.lab_orders?.length > 0 && (
                  <Card title="Lab Orders">
                    {workflow.lab_orders.map((l:any,i:number) => (
                      <Item key={`lab-${i}`} label={l.test} sub={l.urgency} detail={l.rationale} conf={l.confidence} accepted={accepted} onToggle={()=>toggle(`lab-${i}`)} />
                    ))}
                  </Card>
                )}
                {workflow.referrals?.length > 0 && (
                  <Card title="Referrals">
                    {workflow.referrals.map((r:any,i:number) => (
                      <Item key={`ref-${i}`} label={r.specialty} sub={r.urgency} detail={r.rationale} conf={r.confidence} accepted={accepted} onToggle={()=>toggle(`ref-${i}`)} />
                    ))}
                  </Card>
                )}
                {workflow.follow_up?.timing && (
                  <div style={{padding:12,background:'var(--color-neutral-50)',borderRadius:8}}>
                    <strong>Follow-up:</strong> {workflow.follow_up.timing} — {workflow.follow_up.reason}
                  </div>
                )}
              </div>
            )}

            {tab === 'rx' && rx && (
              <div>
                {rx.warnings?.length > 0 && rx.warnings.map((w:string,i:number) => (
                  <div key={i} style={{padding:8,marginBottom:8,background:'var(--color-error-light)',borderRadius:4,color:'var(--color-error)',fontSize:14}}>{w}</div>
                ))}
                {rx.suggestions?.map((p:any,i:number) => (
                  <div key={i} style={{padding:12,marginBottom:8,border:'1px solid var(--color-neutral-200)',borderRadius:8}}>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                      <strong>{p.drug} {p.dose}</strong>
                      <Badge variant={p.confidence>=0.85?'success':'warning'}>{Math.round(p.confidence*100)}%</Badge>
                    </div>
                    <div style={{fontSize:14,color:'var(--color-neutral-500)'}}>{p.route} {p.frequency} x {p.duration}</div>
                    <div style={{fontSize:13,color:'var(--color-neutral-400)',marginTop:4}}>{p.rationale}</div>
                    {p.interactions?.length > 0 && p.interactions.map((w:string,j:number)=><div key={j} style={{color:'var(--color-error)',fontSize:12,marginTop:2}}>{w}</div>)}
                    {p.allergy_check?.length > 0 && p.allergy_check.map((w:string,j:number)=><div key={j} style={{color:'var(--color-error)',fontSize:12,marginTop:2}}>{w}</div>)}
                  </div>
                ))}
              </div>
            )}

            {tab === 'labs' && labs && (
              <div>
                {labs.suggestions?.map((l:any,i:number) => (
                  <div key={i} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:12,borderBottom:'1px solid var(--color-neutral-100)'}}>
                    <div>
                      <strong>{l.test}</strong>
                      <div style={{fontSize:13,color:'var(--color-neutral-400)'}}>{l.rationale}</div>
                    </div>
                    <Badge variant={l.urgency==='stat'?'error':l.urgency==='urgent'?'warning':'info'}>{l.urgency}</Badge>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

function Item({label,sub,detail,conf,accepted,onToggle}:any) {
  const key = `${label}-${sub}`;
  return (
    <div onClick={onToggle} style={{display:'flex',alignItems:'flex-start',gap:8,padding:8,marginBottom:4,borderRadius:6,cursor:'pointer',border:accepted.has(key)?'2px solid var(--color-success)':'1px solid var(--color-neutral-200)',background:accepted.has(key)?'var(--color-success-light)':'#fff'}}>
      <input type="checkbox" checked={accepted.has(key)} onChange={()=>{}} style={{marginTop:3}} />
      <div style={{flex:1}}>
        <div style={{display:'flex',alignItems:'center',gap:6}}>
          <strong style={{fontSize:14}}>{label}</strong>
          {sub && <Badge variant="neutral">{sub}</Badge>}
          <Badge variant={conf>=0.85?'success':conf>=0.6?'warning':'error'}>{Math.round(conf*100)}%</Badge>
        </div>
        <div style={{fontSize:12,color:'var(--color-neutral-400)',marginTop:2}}>{detail}</div>
      </div>
    </div>
  );
}

const el = document.getElementById('workflow-root');
if (el) createRoot(el).render(<WorkflowPanel />);
